const COLORS = [
  'rgba(54,162,235,0.8)', 'rgba(255,99,132,0.8)', 'rgba(75,192,192,0.8)',
  'rgba(255,159,64,0.8)', 'rgba(153,102,255,0.8)', 'rgba(255,205,86,0.8)',
  'rgba(201,203,207,0.8)', 'rgba(0,163,136,0.8)'
];

function detectSheet(row) {
  const keys = Object.keys(row).map(k => k.toLowerCase());
  if (keys.some(k => k.includes('rank_organic') || k.includes('url_hostname'))) return 'ranking';
  if (keys.some(k => k.includes('segment.transaction') || (k.includes('segment') && !k.includes('asset')))) return 'transaction';
  if (keys.some(k => k.includes('segment.asset') || k.includes('asset'))) return 'asset';
  if (keys.some(k => k === 'type' || k.includes('brand') || k.includes('nonbrand'))) return 'audience';
  if (keys.includes('volume') && (keys.includes('month') || keys.includes('year'))) return 'global';
  return null;
}

const all = $input.all().map(i => i.json);
const sheets = { global: [], transaction: [], asset: [], ranking: [], audience: [] };
for (const row of all) {
  const s = detectSheet(row);
  if (s) sheets[s].push(row);
}

const today = new Date().toISOString().slice(0, 10);
const charts = [];

// 1. demand_global — Line chart
{
  const rows = sheets.global.slice(-24);
  if (rows.length) {
    const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const labels = rows.map(r => `${MONTHS[(+r.month||1)-1]} ${r.year||''}`);
    const data = rows.map(r => +r.volume || 0);
    charts.push({
      chartName: `chart_1_demand_global_${today}.png`,
      chartConfig: {
        type: 'line',
        data: { labels, datasets: [{ label: 'Global Volume', data, borderColor: 'rgba(54,162,235,1)', backgroundColor: 'rgba(54,162,235,0.15)', tension: 0.3, fill: true, pointRadius: 3 }] },
        options: { plugins: { title: { display: true, text: '1. Global Demand — Monthly Volume (last 24 months)', font: { size: 16 } }, legend: { display: false } }, scales: { y: { beginAtZero: false } } }
      }
    });
  }
}

// 2. demand_transaction — Multi-line
{
  const rows = sheets.transaction;
  if (rows.length) {
    const segKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('segment')) || 'segment.transaction';
    const dateKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('date')) || 'date';
    const segments = {};
    for (const r of rows) {
      const s = r[segKey] || 'unknown';
      if (!segments[s]) segments[s] = {};
      segments[s][String(r[dateKey])] = +r.volume || 0;
    }
    const allDates = [...new Set(rows.map(r => String(r[dateKey])))].sort().slice(-18);
    const datasets = Object.entries(segments).map(([seg, byDate], i) => ({ label: seg, data: allDates.map(d => byDate[d] || 0), borderColor: COLORS[i].replace('0.8','1'), backgroundColor: COLORS[i], tension: 0.3, fill: false, pointRadius: 3 }));
    charts.push({
      chartName: `chart_2_demand_transaction_${today}.png`,
      chartConfig: {
        type: 'line',
        data: { labels: allDates, datasets },
        options: { plugins: { title: { display: true, text: '2. Demand by Transaction Segment (last 18 months)', font: { size: 16 } } }, scales: { y: { beginAtZero: false } } }
      }
    });
  }
}

// 3. demand_asset — Horizontal bar
{
  const rows = sheets.asset;
  if (rows.length) {
    const segKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('asset') || k.toLowerCase().includes('segment')) || 'segment.asset';
    const dateKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('date')) || 'date';
    const dates = [...new Set(rows.map(r => String(r[dateKey])))].sort();
    const lastDate = dates[dates.length - 1];
    const lastRows = rows.filter(r => String(r[dateKey]) === lastDate).sort((a, b) => +b.volume - +a.volume);
    charts.push({
      chartName: `chart_3_demand_asset_${today}.png`,
      chartConfig: {
        type: 'bar',
        data: { labels: lastRows.map(r => r[segKey] || 'unknown'), datasets: [{ label: 'Volume', data: lastRows.map(r => +r.volume || 0), backgroundColor: COLORS, borderRadius: 4 }] },
        options: { indexAxis: 'y', plugins: { title: { display: true, text: `4. Demand by Asset Type — ${lastDate}`, font: { size: 16 } }, legend: { display: false } }, scales: { x: { beginAtZero: true } } }
      }
    });
  }
}

// 4. ranking_global_war — Horizontal bar
{
  const rows = sheets.ranking;
  if (rows.length) {
    const dateKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('date')) || 'date';
    const hostKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('host') || k.toLowerCase().includes('url')) || 'url_hostname';
    const rankKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('war') || k.toLowerCase().includes('rank')) || 'rank_organic_war';
    const dates = [...new Set(rows.map(r => String(r[dateKey])))].sort();
    const lastDate = dates[dates.length - 1];
    const lastRows = rows.filter(r => String(r[dateKey]) === lastDate).sort((a, b) => +b[rankKey] - +a[rankKey]).slice(0, 10);
    const labels = lastRows.map(r => (r[hostKey] || 'unknown').replace('www.', ''));
    const bgColors = labels.map(l => l.toLowerCase().includes('seloger') ? 'rgba(255,99,132,0.85)' : 'rgba(54,162,235,0.7)');
    charts.push({
      chartName: `chart_4_ranking_war_${today}.png`,
      chartConfig: {
        type: 'bar',
        data: { labels, datasets: [{ label: 'WAR Score', data: lastRows.map(r => +r[rankKey] || 0), backgroundColor: bgColors, borderRadius: 4 }] },
        options: { indexAxis: 'y', plugins: { title: { display: true, text: `3. SEO Ranking (WAR Score) — ${lastDate}`, font: { size: 16 } }, legend: { display: false } }, scales: { x: { beginAtZero: true } } }
      }
    });
  }
}

// 5. audience — Doughnut
{
  const rows = sheets.audience;
  if (rows.length) {
    const dateKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('date')) || 'date';
    const typeKey = Object.keys(rows[0]).find(k => k.toLowerCase() === 'type' || k.toLowerCase().includes('brand')) || 'type';
    const dates = [...new Set(rows.map(r => String(r[dateKey])))].sort();
    const lastDate = dates[dates.length - 1];
    const lastRows = rows.filter(r => String(r[dateKey]) === lastDate);
    charts.push({
      chartName: `chart_5_audience_${today}.png`,
      chartConfig: {
        type: 'doughnut',
        data: { labels: lastRows.map(r => r[typeKey] || 'unknown'), datasets: [{ data: lastRows.map(r => +r.clicks || +r.volume || 0), backgroundColor: COLORS, borderWidth: 2 }] },
        options: { plugins: { title: { display: true, text: `5. Audience Split — ${lastDate}`, font: { size: 16 } }, legend: { position: 'bottom' } } }
      }
    });
  }
}

return charts.map(c => ({ json: c }));
